import{_ as e,o,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F13: 資本支出效能與股利防禦 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3189_景碩/20260423/F13_資本支出效能與股利防禦_投資研究員_審計報告.md","filePath":"審計報告庫/財務審計/3189_景碩/20260423/F13_資本支出效能與股利防禦_投資研究員_審計報告.md"}'),n={name:"審計報告庫/財務審計/3189_景碩/20260423/F13_資本支出效能與股利防禦_投資研究員_審計報告.md"};function i(l,a,_,s,d,c){return o(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="f13-資本支出效能與股利防禦-投資研究員-審計報告" tabindex="-1">F13: 資本支出效能與股利防禦 - 投資研究員 審計報告 <a class="header-anchor" href="#f13-資本支出效能與股利防禦-投資研究員-審計報告" aria-label="Permalink to &quot;F13: 資本支出效能與股利防禦 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>審計景碩資本支出效率（CapEx/營收比、ROIC趨勢）及股利政策防禦等級，評估擴產與股東還報的平衡性。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>景碩2022-2024年資本支出逾200億推升折舊，但營收同步擴張。2021-2024年累計現金股利57.04億，佔同期EPS約50.8%；惟2024年配發率僅17.9%為防禦弱點，反映管理層傾向保留現金以因應擴產債務。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：B（可）</strong></p><p>ROIC自2022年4.1%降至2023年0.8%後回升至2024年2.7%、2025年達4.0%，呈V型復甦。折舊/營收比自18.7%降至16.1%。股利面，2024年EPS 1.74元僅配0.68元，配發率17.9%且每股FCF為-1.24元。以2025年預估EPS 5-6元、配發率理論回升至30-35%計，預估殖利率2.5-3.0%，仍低於PCB同業均值3.5%。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>一、資本支出效率量化評估。</strong></p><p>以2022-2025年為觀測窗口，資本支出集中於ABF擴產：2022年53.2億、2023年86.1億、2024年62.1億、2025年61.2億，四年合計約262.6億，對應營收由264億增至393.5億，邊際營收/CapEx比約0.64倍。ROC同期為4.1%、0.8%、2.7%、4.0%，折舊從49.5億增至71.6億，折舊/營收比從18.7%降至16.1%。總資產週轉率從0.42倍降至0.39倍後回升至0.46倍，擴產資產陸續貢獻營收。</p><p><strong>二、股利政策與股東權益防禦。</strong></p><p>現金股利自2021年高峰3.22元逐年遞減：2022年1.90元、2023年1.50元、2024年0.68元，與EPS趨勢一致。2024年配發率僅17.9%，遠低於2021年56.4%。股利安全性檢視：2024年每股FCF為-1.24元，配息須以借款支應。2025年雖營運現金流80.9億超越CapEx 61.2億，每股FCF轉正約2.7元，但全年折舊71.6億仍高於資本支出。若2026年AI需求趨緩，營運現金流可能再度無法Cover折舊，配息維持或調升均面臨資金壓力。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>（一）資本支出效率值中性樂觀。</strong> 景碩本輪CapEx週期約262億，2025年營收393.5億、毛利率21.1%、營利率6.8%，ROC回升至4.0%。ABF載板佔營收46%且受AI ASIC需求推動，產能利用率可維持高檔。</p><p><strong>（二）股利防禦強烈不足。</strong> 2024年現金股利僅0.68元，以140元股價計殖利率0.49%，遠低於台股均值3-4%。若考量2022-2024年累計EPS僅5.05元、配發率約80%（含超額配發），已透支財務彈性。管理層應優先恢復配發率至30%以上，否則將引發長線投資人減碼。</p><p><strong>（三）空頭視角。</strong> 若2026下半年AI資本支出循環轉向保守，ABF載板供需缺口收斂，262億擴產的折舊壓力將在2027年達高峰（預估年折舊90-100億），壓縮營利率。股利面即便配發率拉升至35%，預估每股股利1.75-2.1元，殖利率僅1.25-1.5%。管理層未釋出現金回流路徑圖，市場持續給予折價估值（P/B 1.6倍低於五年均值1.8倍）。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py finance 3189 2022-01-01 2026-04-23 --df</code> (科目：營業收入、營業利益、稅前淨利、EPS、股利、折舊)</li><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py cash_flow 3189 2022-01-01 2025-12-31 --df</code> (科目：取得不動產廠房及設備、營運現金流、自由現金流)</li><li><code>數據採集器查詢</code>: <code>/Users/kaipro/.openclaw/skills/finmind/數據採集器.py balance_sheet 3189 2022-01-01 2025-12-31 --df</code> (科目：總資產、有息負債、負債比、ROIC、ROC)</li><li><code>Goodinfo 景碩</code>: 股利政策歷年資料 (現金股利、股票股利、配發率、殖利率)</li></ul>',19)])])}const f=e(n,[["render",i]]);export{h as __pageData,f as default};
